CREATE PROCEDURE dbo.Account_BulkMoveUnderParent_Alt
    @NewParentCode   NVARCHAR(50),
    @AccountCodesCsv NVARCHAR(MAX),       -- مثال:  '220501','220502','220503'
    @Reason          NVARCHAR(400) = NULL,
    @BatchId         UNIQUEIDENTIFIER = NULL,
    @MovedByUserId   INT = NULL,
    @MovedByUser     NVARCHAR(100) = NULL,
    @AppName         NVARCHAR(100) = N'VB6'
AS
BEGIN
    SET NOCOUNT ON; SET XACT_ABORT ON;

    IF OBJECT_ID('tempdb..#list') IS NOT NULL DROP TABLE #list;
    CREATE TABLE #list (Account_Code NVARCHAR(50) PRIMARY KEY);

    DECLARE @xml XML;
    SET @xml = CAST(('<r><i>' + REPLACE(REPLACE(@AccountCodesCsv, '''', ''), ',', '</i><i>') + '</i></r>') AS XML);

    INSERT INTO #list(Account_Code)
    SELECT DISTINCT LTRIM(RTRIM(T.c.value('.', 'nvarchar(50)')))
    FROM @xml.nodes('/r/i') AS T(c)
    WHERE LTRIM(RTRIM(T.c.value('.', 'nvarchar(50)'))) <> N'';

    IF NOT EXISTS (SELECT 1 FROM #list) RETURN;

    BEGIN TRY
        BEGIN TRAN;

        DECLARE @ParentSerial NVARCHAR(200), @LevelNo INT, @Digits INT;

        SELECT @ParentSerial = A.Account_Serial
        FROM dbo.ACCOUNTS AS A WITH (UPDLOCK, HOLDLOCK)
        WHERE A.Account_Code = @NewParentCode;

        IF @ParentSerial IS NULL
        BEGIN
            RAISERROR(N'الأب المحدد لا يملك Serial.', 16, 1);
            ROLLBACK TRAN; RETURN;
        END

        SELECT TOP (1) @LevelNo = L.[Level]
        FROM dbo.AccountsLevelsDetails AS L
        WHERE LEN(@ParentSerial) = (SELECT SUM(NoOfDigits) FROM dbo.AccountsLevelsDetails L2 WHERE L2.[Level] <= L.[Level])
        ORDER BY L.[Level];

        SET @LevelNo = ISNULL(@LevelNo, 0) + 1;

        SELECT @Digits = NoOfDigits FROM dbo.AccountsLevelsDetails WHERE [Level] = @LevelNo;
        IF @Digits IS NULL OR @Digits <= 0
        BEGIN
            RAISERROR(N'تعذّر تحديد عدد الخانات للمستوى التالي.', 16, 1);
            ROLLBACK TRAN; RETURN;
        END

        DECLARE @Base INT;
        SELECT @Base = ISNULL(MAX(CAST(RIGHT(Account_Serial, @Digits) AS INT)), 0)
        FROM dbo.ACCOUNTS WITH (UPDLOCK, HOLDLOCK)
        WHERE Parent_Account_Code = @NewParentCode
          AND Account_Serial LIKE @ParentSerial + N'%'
          AND LEN(Account_Serial) = LEN(@ParentSerial) + @Digits;

        ;WITH cte AS
        (
            SELECT A.Account_Code,
                   ROW_NUMBER() OVER (ORDER BY A.Account_Code) AS rn
            FROM dbo.ACCOUNTS A
            JOIN #list L ON L.Account_Code = A.Account_Code
            WHERE ISNULL(A.Parent_Account_Code, N'') <> @NewParentCode
        ),
        toUpdate AS
        (
            SELECT U.Account_Code,
                   NewSerial = @ParentSerial 
                              + RIGHT(REPLICATE(N'0', @Digits) 
                              + CONVERT(VARCHAR(20), @Base + rn), @Digits)
            FROM cte AS U
        )
        UPDATE A
        SET A.Parent_Account_Code = @NewParentCode,
            A.Account_Serial      = TU.NewSerial
        OUTPUT
            DELETED.Account_Code,
            DELETED.Parent_Account_Code,
            DELETED.Account_Serial,
            INSERTED.Parent_Account_Code,
            INSERTED.Account_Serial,
            @Reason,
            @BatchId,
            @MovedByUserId,
            @MovedByUser,
            HOST_NAME(),
            @AppName,
            SYSDATETIME()
        INTO dbo.AccountMoveLog
        (
            Account_Code, OldParentCode, OldSerial,
            NewParentCode, NewSerial,
            Reason, BatchId, MovedByUserId, MovedByUserName, Workstation, AppName, MovedAt
        )
        FROM dbo.ACCOUNTS A
        JOIN toUpdate TU ON TU.Account_Code = A.Account_Code;

        COMMIT TRAN;
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK TRAN;
        DECLARE @msg NVARCHAR(4000) = ERROR_MESSAGE();
        RAISERROR(@msg, 16, 1);
    END CATCH
END

CREATE PROCEDURE dbo.Account_MoveUnderParent
    @AccountCode    NVARCHAR(50),
    @NewParentCode  NVARCHAR(50),
    @Reason         NVARCHAR(400) = NULL,
    @BatchId        UNIQUEIDENTIFIER = NULL,
    @MovedByUserId  INT = NULL,
    @MovedByUser    NVARCHAR(100) = NULL,
    @AppName        NVARCHAR(100) = N'Dynamic',
    @NewSerial      NVARCHAR(200) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    DECLARE @OldParent NVARCHAR(50), @OldSerial NVARCHAR(200);
    DECLARE @ParentSerial NVARCHAR(200);
    DECLARE @LevelNo INT, @Digits INT, @MaxTail INT, @NextNum INT;

    BEGIN TRY
        BEGIN TRAN;

        /* قفل صف الحساب أثناء التحديث */
        SELECT 
            @OldParent = Parent_Account_Code,
            @OldSerial = Account_Serial
        FROM dbo.ACCOUNTS WITH (UPDLOCK, HOLDLOCK)
        WHERE Account_Code = @AccountCode;

        /* سيريال الأب الجديد */
        SELECT @ParentSerial = Account_Serial
        FROM dbo.ACCOUNTS
        WHERE Account_Code = @NewParentCode;

        IF @ParentSerial IS NULL
        BEGIN
            RAISERROR(N'الأب المحدد لا يملك Serial.', 16, 1);
            ROLLBACK TRAN; RETURN;
        END

        /* تحديد مستوى الأب ثم مستوى الابن (Level الأب + 1)
           حساب مستوى الأب يتم بمطابقة طول سيرياله مع مجموع NoOfDigits حتى هذا المستوى */
        SELECT TOP (1) @LevelNo = L.[Level]
        FROM dbo.AccountsLevelsDetails AS L
        WHERE LEN(@ParentSerial) = (
            SELECT SUM(NoOfDigits) FROM dbo.AccountsLevelsDetails L2 WHERE L2.[Level] <= L.[Level]
        )
        ORDER BY L.[Level];

        SET @LevelNo = ISNULL(@LevelNo, 0) + 1;

        SELECT @Digits = NoOfDigits 
        FROM dbo.AccountsLevelsDetails 
        WHERE [Level] = @LevelNo;

        IF @Digits IS NULL OR @Digits <= 0
        BEGIN
            RAISERROR(N'تعذّر تحديد عدد الخانات للمستوى التالي.', 16, 1);
            ROLLBACK TRAN; RETURN;
        END

        /* أكبر ذيل موجود تحت الأب */
        SELECT @MaxTail = MAX(CAST(RIGHT(Account_Serial, @Digits) AS INT))
        FROM dbo.ACCOUNTS
        WHERE Parent_Account_Code = @NewParentCode
          AND Account_Serial LIKE @ParentSerial + N'%'
          AND LEN(Account_Serial) = LEN(@ParentSerial) + @Digits;

        SET @NextNum = ISNULL(@MaxTail, 0) + 1;

        /* توليد السيريال الجديد وضمان عدم التعارض */
        DECLARE @Tail NVARCHAR(50);
        SET @Tail = RIGHT(REPLICATE(N'0', @Digits) + CONVERT(VARCHAR(20), @NextNum), @Digits);
        SET @NewSerial = @ParentSerial + @Tail;

        WHILE EXISTS (SELECT 1 FROM dbo.ACCOUNTS WHERE Account_Serial = @NewSerial)
        BEGIN
            SET @NextNum = @NextNum + 1;
            SET @Tail = RIGHT(REPLICATE(N'0', @Digits) + CONVERT(VARCHAR(20), @NextNum), @Digits);
            SET @NewSerial = @ParentSerial + @Tail;
        END

        /* التحديث */
        UPDATE dbo.ACCOUNTS
        SET Parent_Account_Code = @NewParentCode,
            Account_Serial      = @NewSerial
        WHERE Account_Code = @AccountCode;

        /* اللوج */
        INSERT INTO dbo.AccountMoveLog
        (Account_Code, OldParentCode, OldSerial, NewParentCode, NewSerial,
         Reason, BatchId, MovedByUserId, MovedByUserName, Workstation, AppName)
        VALUES
        (@AccountCode, @OldParent, @OldSerial, @NewParentCode, @NewSerial,
         @Reason, @BatchId, @MovedByUserId, @MovedByUser, HOST_NAME(), @AppName);

        COMMIT TRAN;
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK TRAN;
        DECLARE @msg NVARCHAR(4000) = ERROR_MESSAGE();
        RAISERROR(@msg, 16, 1);
    END CATCH
END

/*
**	Retrieve the owner object(s) of a given property
*/
create procedure dbo.dt_getobjwithprop
	@property varchar(30),
	@value varchar(255)
as
	set nocount on

	if (@property is null) or (@property = '')
	begin
		raiserror('Must specify a property name.',-1,-1)
		return (1)
	end

	if (@value is null)
		select objectid id from dbo.dtproperties
			where property=@property

	else
		select objectid id from dbo.dtproperties
			where property=@property and value=@value

/*
**	Retrieve the owner object(s) of a given property
*/
create procedure dbo.dt_getobjwithprop_u
	@property varchar(30),
	@uvalue nvarchar(255)
as
	set nocount on

	if (@property is null) or (@property = '')
	begin
		raiserror('Must specify a property name.',-1,-1)
		return (1)
	end

	if (@uvalue is null)
		select objectid id from dbo.dtproperties
			where property=@property

	else
		select objectid id from dbo.dtproperties
			where property=@property and uvalue=@uvalue

create procedure dbo.dt_getpropertiesbyid_vcs
    @id       int,
    @property varchar(64),
    @value    varchar(255) = NULL OUT

as

    set nocount on

    select @value = (
        select value
                from dbo.dtproperties
                where @id=objectid and @property=property
                )

create procedure dbo.dt_getpropertiesbyid_vcs_u
    @id       int,
    @property varchar(64),
    @value    nvarchar(255) = NULL OUT

as

    set nocount on

    select @value = (
        select uvalue
                from dbo.dtproperties
                where @id=objectid and @property=property
                )

CREATE PROCEDURE dbo.ReserveTransactionId
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    DECLARE @lockResult INT;
    DECLARE @maxId BIGINT;
    DECLARE @currentValue BIGINT;
    DECLARE @newStart BIGINT;
    DECLARE @NewId BIGINT;
    DECLARE @sql NVARCHAR(MAX);

    EXEC @lockResult = sys.sp_getapplock
        @Resource = N'ReserveTransactionId_Lock',
        @LockMode = N'Exclusive',
        @LockOwner = N'Session',
        @LockTimeout = 10000;

    IF @lockResult < 0
    BEGIN
        RAISERROR(N'Could not acquire app lock for ReserveTransactionId.', 16, 1);
        RETURN;
    END

    SELECT @maxId = ISNULL(MAX(Transaction_ID), 0)
    FROM dbo.Transactions WITH (HOLDLOCK, UPDLOCK);

    IF NOT EXISTS
    (
        SELECT 1
        FROM sys.sequences
        WHERE name = N'TranIdSeq'
          AND SCHEMA_NAME(schema_id) = N'dbo'
    )
    BEGIN
        SET @newStart = @maxId + 1;
        SET @sql = N'CREATE SEQUENCE dbo.TranIdSeq AS BIGINT START WITH '
                 + CAST(@newStart AS NVARCHAR(30))
                 + N' INCREMENT BY 1;';
        EXEC sys.sp_executesql @sql;
    END

    SELECT @currentValue = CONVERT(BIGINT, current_value)
    FROM sys.sequences
    WHERE name = N'TranIdSeq'
      AND SCHEMA_NAME(schema_id) = N'dbo';

    IF @currentValue <= @maxId
    BEGIN
        SET @newStart = @maxId + 1;
        SET @sql = N'ALTER SEQUENCE dbo.TranIdSeq RESTART WITH '
                 + CAST(@newStart AS NVARCHAR(30)) + N';';
        EXEC sys.sp_executesql @sql;
    END

    SELECT @NewId = NEXT VALUE FOR dbo.TranIdSeq;

    IF EXISTS (SELECT 1 FROM dbo.Transactions WHERE Transaction_ID = @NewId)
    BEGIN
        SELECT @maxId = ISNULL(MAX(Transaction_ID), 0)
        FROM dbo.Transactions WITH (HOLDLOCK, UPDLOCK);

        SET @newStart = @maxId + 1;
        SET @sql = N'ALTER SEQUENCE dbo.TranIdSeq RESTART WITH '
                 + CAST(@newStart AS NVARCHAR(30)) + N';';
        EXEC sys.sp_executesql @sql;

        SELECT @NewId = NEXT VALUE FOR dbo.TranIdSeq;

        IF EXISTS (SELECT 1 FROM dbo.Transactions WHERE Transaction_ID = @NewId)
        BEGIN
            RAISERROR(N'Failed to reserve a unique Transaction_ID.', 16, 1);
            RETURN;
        END
    END

    SELECT CAST(@NewId AS BIGINT) AS NewId;
END

CREATE PROCEDURE dbo.sp__InsertDevLine
    @Table         SYSNAME,
    @NotesID       BIGINT,
    @Account       NVARCHAR(50),
    @Value         DECIMAL(19,6),
    @CreditOrDebit BIT,              -- 0=مدين, 1=دائن
    @RecordDate    DATE,
    @UserID        INT           = NULL,
    @TransactionID BIGINT        = NULL,
    @BranchID      INT           = NULL,
    @Description   NVARCHAR(200) = NULL,
    @IdColumn      SYSNAME       = NULL,     -- مثال: 'Double_Entry_Vouchers_ID'
    @IdValue       BIGINT        = NULL,     -- يُحسب MAX+1 لو مطلوب
    @LineNo        INT           = NULL      -- DEV_ID_Line_No
AS
BEGIN
    SET NOCOUNT ON;

    IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_SCHEMA='dbo' AND TABLE_NAME=@Table)
        RETURN;

    DECLARE @objId INT = OBJECT_ID(QUOTENAME('dbo')+'.'+QUOTENAME(@Table));
    DECLARE @hasIdCol BIT=0, @idIsIdentity BIT=0, @idIsNullable BIT=1;

    IF @IdColumn IS NOT NULL AND COL_LENGTH('dbo.'+@Table, @IdColumn) IS NOT NULL
    BEGIN
        SET @hasIdCol=1;
        SELECT @idIsIdentity = CASE WHEN EXISTS(
                   SELECT 1 FROM sys.identity_columns 
                   WHERE object_id=@objId AND name=@IdColumn) THEN 1 ELSE 0 END;

        SELECT @idIsNullable = c.is_nullable
        FROM sys.columns c
        WHERE c.object_id=@objId AND c.name=@IdColumn;
    END

    -- لو محتاج ID ومش Identity ومش Nullable ومفيش قيمة => MAX+1 (مع قفل)
    IF @hasIdCol=1 AND @idIsIdentity=0 AND @idIsNullable=0 AND @IdValue IS NULL
    BEGIN
        DECLARE @sqlNext NVARCHAR(MAX), @next BIGINT;
        SET @sqlNext = N'SELECT @n = ISNULL(MAX(CAST('+QUOTENAME(@IdColumn)+N' AS BIGINT)),0)+1 FROM dbo.'+QUOTENAME(@Table)+N' WITH (UPDLOCK, HOLDLOCK);';
        EXEC sp_executesql @sqlNext, N'@n BIGINT OUTPUT', @n=@next OUTPUT;
        SET @IdValue = @next;
    END

    -- بناء القوائم
    DECLARE @colList NVARCHAR(MAX)='', @valList NVARCHAR(MAX)='', @sql NVARCHAR(MAX)='';

    IF @hasIdCol=1 AND (@IdValue IS NOT NULL OR @idIsIdentity=0)
    BEGIN
        SET @colList+=','+QUOTENAME(@IdColumn);
        SET @valList+=',@IdValue';
    END

    IF COL_LENGTH('dbo.'+@Table,'DEV_ID_Line_No') IS NOT NULL AND @LineNo IS NOT NULL
    BEGIN
        SET @colList+=',DEV_ID_Line_No';
        SET @valList+=',@LineNo';
    END

    IF COL_LENGTH('dbo.'+@Table,'Notes_ID')        IS NOT NULL BEGIN SET @colList+=',Notes_ID';        SET @valList+=',@NotesID';       END
    IF COL_LENGTH('dbo.'+@Table,'Account_Code')    IS NOT NULL BEGIN SET @colList+=',Account_Code';    SET @valList+=',@Account';       END
    IF COL_LENGTH('dbo.'+@Table,'Value')           IS NOT NULL BEGIN SET @colList+=',Value';           SET @valList+=',@Value';         END
    IF COL_LENGTH('dbo.'+@Table,'Credit_Or_Debit') IS NOT NULL BEGIN SET @colList+=',Credit_Or_Debit'; SET @valList+=',@CreditOrDebit'; END
    IF COL_LENGTH('dbo.'+@Table,'RecordDate')      IS NOT NULL BEGIN SET @colList+=',RecordDate';      SET @valList+=',@RecordDate';    END
    IF COL_LENGTH('dbo.'+@Table,'UserID')          IS NOT NULL BEGIN SET @colList+=',UserID';          SET @valList+=',@UserID';        END
    IF COL_LENGTH('dbo.'+@Table,'Transaction_ID')  IS NOT NULL BEGIN SET @colList+=',Transaction_ID';  SET @valList+=',@TransactionID'; END
    IF COL_LENGTH('dbo.'+@Table,'BranchId')        IS NOT NULL BEGIN SET @colList+=',BranchId';        SET @valList+=',@BranchID';      END
    IF COL_LENGTH('dbo.'+@Table,'Branch_ID')       IS NOT NULL BEGIN SET @colList+=',Branch_ID';       SET @valList+=',@BranchID';      END
    IF COL_LENGTH('dbo.'+@Table,'Des')             IS NOT NULL BEGIN SET @colList+=',Des';             SET @valList+=',@Description';   END
    ELSE IF COL_LENGTH('dbo.'+@Table,'Description')IS NOT NULL BEGIN SET @colList+=',Description';     SET @valList+=',@Description';   END

    SET @colList = STUFF(@colList,1,1,'');
    SET @valList = STUFF(@valList,1,1,'');

    SET @sql = N'INSERT INTO dbo.'+QUOTENAME(@Table)+' ('+@colList+') VALUES ('+@valList+');';

    EXEC sp_executesql @sql,
      N'@IdValue bigint,@LineNo int,@NotesID bigint,@Account nvarchar(50),@Value decimal(19,6),@CreditOrDebit bit,@RecordDate date,@UserID int,@TransactionID bigint,@BranchID int,@Description nvarchar(200)',
      @IdValue=@IdValue,@LineNo=@LineNo,@NotesID=@NotesID,@Account=@Account,@Value=@Value,@CreditOrDebit=@CreditOrDebit,@RecordDate=@RecordDate,@UserID=@UserID,@TransactionID=@TransactionID,@BranchID=@BranchID,@Description=@Description;
END

CREATE PROCEDURE dbo.sp_CreateIssueVoucherJE
    @IssueTransactionID BIGINT,           -- حركة الصرف (19)
    @NoteID             BIGINT,           -- NoteID المرتبط بالسند
    @UserID             INT     = NULL,
    @CustomDesc         NVARCHAR(200) = NULL,
    @StoreFieldName     SYSNAME = N'Account_Code',  -- عمود الحساب في TblStore
    @StartLineNo        INT     = 1                 -- يبدأ الترقيم من 1
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @BranchID INT, @BillDate DATE, @StoreID INT;
    SELECT
        @BranchID = t.BranchId,
        @BillDate = t.Transaction_Date,
        @StoreID  = t.StoreID
    FROM dbo.Transactions t
    WHERE t.Transaction_ID=@IssueTransactionID AND t.Transaction_Type=19;

    IF @BranchID IS NULL
    BEGIN
        RAISERROR(N'Issue transaction not found or not type (19).',16,1);
        RETURN;
    END

    DECLARE @TotalCost DECIMAL(19,6);
    SELECT @TotalCost = SUM(d.Quantity * d.Price)
    FROM dbo.Transaction_Details d
    WHERE d.Transaction_ID=@IssueTransactionID;

    IF ISNULL(@TotalCost,0)=0 RETURN;

    -- أطراف القيد
    DECLARE @AccCredit NVARCHAR(50),  -- الدائن = حساب المخزن من TblStore
            @AccDebit  NVARCHAR(50);  -- المدين = a1 من الفرع

    DECLARE @tmp NVARCHAR(50);
    EXEC dbo.sp_GetStoreAccount @StoreID, @StoreFieldName, @tmp OUTPUT;   -- يقرأ من TblStore
    SET @AccCredit = @tmp;

    SELECT @AccDebit = dbo.fn_GetBranchAccountCode(@BranchID, 1);         -- a1 من الفروع

    IF @AccCredit IS NULL RAISERROR(N'Store account not defined/invalid.',16,1);
    IF @AccDebit  IS NULL RAISERROR(N'Branch a1 (COGS) account not defined/invalid.',16,1);

    -- امسح أي قيد قديم لنفس NoteID (Idempotent)
    IF OBJECT_ID('dbo.DOUBLE_ENTRY_VOUCHERS','U') IS NOT NULL
       AND COL_LENGTH('dbo.DOUBLE_ENTRY_VOUCHERS', 'Notes_ID') IS NOT NULL
    BEGIN
        EXEC sys.sp_executesql
            N'DELETE FROM dbo.DOUBLE_ENTRY_VOUCHERS WHERE Notes_ID = @NoteID;',
            N'@NoteID BIGINT',
            @NoteID = @NoteID;
    END;
    IF OBJECT_ID('dbo.DOUBLE_ENTREY_VOUCHERS','U') IS NOT NULL
       AND COL_LENGTH('dbo.DOUBLE_ENTREY_VOUCHERS', 'Notes_ID') IS NOT NULL
    BEGIN
        EXEC sys.sp_executesql
            N'DELETE FROM dbo.DOUBLE_ENTREY_VOUCHERS WHERE Notes_ID = @NoteID;',
            N'@NoteID BIGINT',
            @NoteID = @NoteID;
    END;

    -- أوصاف جاهزة (بدل تمرير تعبير داخل EXEC)
    DECLARE @DescDebit  NVARCHAR(200), @DescCredit NVARCHAR(200);
    SET @DescDebit  = ISNULL(@CustomDesc, N'Issue voucher - debit branch a1');
    SET @DescCredit = ISNULL(@CustomDesc, N'Issue voucher - credit store account');

    -- ترقيم السطور
    DECLARE @ln INT = @StartLineNo;

    -- (1) مدين: a1
    EXEC dbo.sp__InsertDevLine 
         @Table='DOUBLE_ENTRY_VOUCHERS',
         @NotesID=@NoteID,@Account=@AccDebit,@Value=@TotalCost,@CreditOrDebit=0,
         @RecordDate=@BillDate,@UserID=@UserID,@TransactionID=@IssueTransactionID,@BranchID=@BranchID,
         @Description=@DescDebit,
         @IdColumn='Double_Entry_Vouchers_ID', @IdValue=NULL,
         @LineNo=@ln;

    EXEC dbo.sp__InsertDevLine 
         @Table='DOUBLE_ENTREY_VOUCHERS',
         @NotesID=@NoteID,@Account=@AccDebit,@Value=@TotalCost,@CreditOrDebit=0,
         @RecordDate=@BillDate,@UserID=@UserID,@TransactionID=@IssueTransactionID,@BranchID=@BranchID,
         @Description=@DescDebit,
         @IdColumn='Double_Entry_Vouchers_ID', @IdValue=NULL,
         @LineNo=@ln;

    SET @ln = @ln + 1;

    -- (2) دائن: حساب المخزن
    EXEC dbo.sp__InsertDevLine 
         @Table='DOUBLE_ENTRY_VOUCHERS',
         @NotesID=@NoteID,@Account=@AccCredit,@Value=@TotalCost,@CreditOrDebit=1,
         @RecordDate=@BillDate,@UserID=@UserID,@TransactionID=@IssueTransactionID,@BranchID=@BranchID,
         @Description=@DescCredit,
         @IdColumn='Double_Entry_Vouchers_ID', @IdValue=NULL,
         @LineNo=@ln;

    EXEC dbo.sp__InsertDevLine 
         @Table='DOUBLE_ENTREY_VOUCHERS',
         @NotesID=@NoteID,@Account=@AccCredit,@Value=@TotalCost,@CreditOrDebit=1,
         @RecordDate=@BillDate,@UserID=@UserID,@TransactionID=@IssueTransactionID,@BranchID=@BranchID,
         @Description=@DescCredit,
         @IdColumn='Double_Entry_Vouchers_ID', @IdValue=NULL,
         @LineNo=@ln;
END

CREATE PROCEDURE dbo.sp_GetBranchAccountCode
    @BranchID     INT,
    @AccountIndex INT,              -- 0,1,2,...
    @Prefix       NVARCHAR(10)='a', -- افتراضي a => أعمدة مثل a0/a1
    @AccountCode  NVARCHAR(50) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @col SYSNAME = @Prefix + CAST(@AccountIndex AS VARCHAR(10));
    DECLARE @sql NVARCHAR(MAX);

    -- لو فيه branch_id هنفلتر، وإلا هنرجّع أول صف (توافقاً مع كودك القديم)
    IF COL_LENGTH('dbo.branches','branch_id') IS NOT NULL
        SET @sql = N'SELECT TOP(1) @out=' + QUOTENAME(@col) + N' FROM dbo.branches WHERE branch_id=@bid;';
    ELSE IF COL_LENGTH('dbo.branches','BranchId') IS NOT NULL
        SET @sql = N'SELECT TOP(1) @out=' + QUOTENAME(@col) + N' FROM dbo.branches WHERE BranchId=@bid;';
    ELSE
        SET @sql = N'SELECT TOP(1) @out=' + QUOTENAME(@col) + N' FROM dbo.branches;';

    SET @AccountCode = NULL;
    EXEC sp_executesql @sql, N'@bid int, @out nvarchar(50) OUTPUT', @bid=@BranchID, @out=@AccountCode OUTPUT;

    -- تحقق من صلاحية الحساب (بديل CheckAccountToJE)
    IF @AccountCode IS NULL OR NOT EXISTS (SELECT 1 FROM dbo.ACCOUNTS WHERE Account_Code=@AccountCode)
        SET @AccountCode = NULL;
END

CREATE PROCEDURE dbo.sp_GetStoreAccount
    @StoreID     INT,
    @FieldName   SYSNAME = N'Account_Code',   -- اسم العمود في TblStore
    @AccountCode NVARCHAR(50) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    IF NOT EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS 
                   WHERE TABLE_SCHEMA='dbo' AND TABLE_NAME='TblStore' AND COLUMN_NAME=@FieldName)
    BEGIN
        SET @AccountCode = NULL;
        RETURN;
    END

    DECLARE @sql NVARCHAR(MAX) = N'SELECT @out=' + QUOTENAME(@FieldName) + N' FROM dbo.TblStore WHERE StoreID=@sid;';
    SET @AccountCode = NULL;
    EXEC sp_executesql @sql, N'@sid int, @out nvarchar(50) OUTPUT', @sid=@StoreID, @out=@AccountCode OUTPUT;

    -- (اختياري) تأكيد وجود الحساب في شجرة الحسابات
    IF @AccountCode IS NULL OR NOT EXISTS (SELECT 1 FROM dbo.ACCOUNTS WHERE Account_Code=@AccountCode)
        SET @AccountCode = NULL;
END

----------------------------------------------------
-- ستورد بروسيجر الصيانة السريعة/الخفيفة
----------------------------------------------------
CREATE PROCEDURE dbo.usp_QuickDbMaintenance
(
      @ReorganizeFrom   FLOAT = 10    -- من نسبة فراجمنتشن كام يبدأ يعمل REORGANIZE
    , @MinPageCount     INT   = 200   -- تجاهل الإندكسات الصغيرة (أقل من كذا صفحة)
    , @PreviewOnly      BIT   = 0     -- لو 1: يطبع الأوامر بس من غير تنفيذ (للمراجعة)
)
AS
BEGIN
    SET NOCOUNT ON;

    PRINT '===============================================';
    PRINT 'بدء الصيانة السريعة للداتا بيز: ' + DB_NAME();
    PRINT 'التاريخ/الوقت: ' + CONVERT(NVARCHAR(30), GETDATE(), 120);
    PRINT '===============================================';

    ------------------------------------------------
    -- 1) REORGANIZE للإندكسات ذات الفراجمنتشن المتوسط
    ------------------------------------------------
    PRINT 'الخطوة 1: حساب الفراجمنتشن وعمل REORGANIZE للإندكسات المتفرجمنتة...';

    IF OBJECT_ID('tempdb..#FragQuick') IS NOT NULL DROP TABLE #FragQuick;

    SELECT 
          t.name      AS TableName
        , s.name      AS SchemaName
        , i.name      AS IndexName
        , ips.index_id
        , ips.avg_fragmentation_in_percent AS FragPercent
        , ips.page_count
    INTO #FragQuick
    FROM sys.dm_db_index_physical_stats(DB_ID(), NULL, NULL, NULL, 'LIMITED') ips
    JOIN sys.indexes i   ON ips.object_id = i.object_id AND ips.index_id = i.index_id
    JOIN sys.tables t    ON t.object_id  = i.object_id
    JOIN sys.schemas s   ON t.schema_id = s.schema_id
    WHERE 
        i.type IN (1,2)              -- clustered, nonclustered
        AND ips.page_count >= @MinPageCount
        AND t.is_ms_shipped = 0
        AND ips.avg_fragmentation_in_percent >= @ReorganizeFrom;

    DECLARE 
          @TableName   SYSNAME
        , @SchemaName  SYSNAME
        , @IndexName   SYSNAME
        , @IndexId     INT
        , @Frag        FLOAT
        , @SQL         NVARCHAR(MAX);

    DECLARE curQuick CURSOR LOCAL FAST_FORWARD FOR
        SELECT TableName, SchemaName, IndexName, index_id, FragPercent
        FROM #FragQuick
        ORDER BY FragPercent DESC;

    OPEN curQuick;
    FETCH NEXT FROM curQuick INTO @TableName, @SchemaName, @IndexName, @IndexId, @Frag;

    WHILE @@FETCH_STATUS = 0
    BEGIN
        SET @SQL = N'ALTER INDEX [' + @IndexName + N'] ON [' 
                    + @SchemaName + N'].[' + @TableName + N'] REORGANIZE;';

        PRINT '-- Frag = ' + CONVERT(NVARCHAR(10), @Frag) 
              + ' | ' + @SchemaName + '.' + @TableName + ' -> ' + @IndexName;
        PRINT @SQL;

        IF @PreviewOnly = 0
        BEGIN
            BEGIN TRY
                EXEC (@SQL);
            END TRY
            BEGIN CATCH
                PRINT 'خطأ أثناء REORGANIZE للإندكس: '
                      + ISNULL(@SchemaName,'') + '.' + ISNULL(@TableName,'')
                      + ' - ' + ISNULL(@IndexName,'')
                      + ' => ' + ERROR_MESSAGE();
            END CATCH;
        END

        FETCH NEXT FROM curQuick INTO @TableName, @SchemaName, @IndexName, @IndexId, @Frag;
    END

    CLOSE curQuick;
    DEALLOCATE curQuick;

    PRINT 'انتهاء خطوة REORGANIZE.';
    PRINT '-----------------------------------------------';

    ------------------------------------------------
    -- 2) تحديث إحصائيات خفيف باستخدام sp_updatestats
    ------------------------------------------------
    PRINT 'الخطوة 2: تحديث الإحصائيات باستخدام sp_updatestats (خفيفة)...';

    IF @PreviewOnly = 0
    BEGIN
        -- sp_updatestats يقوم بتحديث الإحصائيات للجداول التي تم تعديل بياناتها فقط
        EXEC sp_updatestats;
    END
    ELSE
    BEGIN
        PRINT 'PreviewOnly = 1 => تم تخطي تنفيذ sp_updatestats (عرض فقط).';
    END

    PRINT 'انتهاء الصيانة السريعة للداتا بيز.';
    PRINT '===============================================';

END

CREATE PROCEDURE dbo.usp_UltimateDbOptimizer
(
    -- ═══════════════════════════════════════════════════════════════
    -- إعدادات صيانة الإندكسات
    -- ═══════════════════════════════════════════════════════════════
      @RebuildThreshold         FLOAT   = 30
    , @ReorganizeThreshold      FLOAT   = 5
    , @MinPageCount             INT     = 100
    , @OnlineRebuild            BIT     = 0
    , @FillFactor               INT     = 80

    -- ═══════════════════════════════════════════════════════════════
    -- إعدادات الجداول Heap
    -- ═══════════════════════════════════════════════════════════════
    , @FixHeapTables            BIT     = 1
    , @HeapMinRows              INT     = 100

    -- ═══════════════════════════════════════════════════════════════
    -- إعدادات إنشاء الإندكسات الناقصة
    -- ═══════════════════════════════════════════════════════════════
    , @CreateMissingIndexes     BIT     = 1
    , @MissingIndexMinReads     BIGINT  = 500
    , @MissingIndexMinImpact    FLOAT   = 40
    , @MaxMissingIndexesToCreate INT    = 15

    -- ═══════════════════════════════════════════════════════════════
    -- إعدادات حذف الإندكسات
    -- ═══════════════════════════════════════════════════════════════
    , @DropUnusedIndexes        BIT     = 0
    , @DropDuplicateIndexes     BIT     = 1

    -- ═══════════════════════════════════════════════════════════════
    -- ★★★ إعدادات جديدة لإصلاح مشاكل الأداء ★★★
    -- ═══════════════════════════════════════════════════════════════
    , @FixServerSettings        BIT     = 1         -- إصلاح إعدادات السيرفر (MAXDOP, Memory)
    , @FixTempDB                BIT     = 1         -- إصلاح مشكلة TempDB (LATCH_EX)
    , @FixParallelism           BIT     = 1         -- إصلاح مشكلة CXPACKET
    , @ShrinkLogFile            BIT     = 1         -- تقليص Log File
    , @OptimizeMemory           BIT     = 1         -- تحسين إعدادات الذاكرة

    -- ═══════════════════════════════════════════════════════════════
    -- إعدادات عامة
    -- ═══════════════════════════════════════════════════════════════
    , @FixDbSettings            BIT     = 1
    , @UpdateStatistics         BIT     = 1
    , @ClearBadPlans            BIT     = 1
    , @ClearWaitStats           BIT     = 0         -- مسح Wait Stats بعد الإصلاح
    , @AnalyzeWaitStats         BIT     = 1
    , @TopQueries               INT     = 30
    , @PreviewOnly              BIT     = 0
    , @VerboseOutput            BIT     = 1
)
AS
BEGIN
    SET NOCOUNT ON;
    SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
    SET ANSI_WARNINGS OFF;

    -- ═══════════════════════════════════════════════════════════════
    -- متغيرات عامة
    -- ═══════════════════════════════════════════════════════════════
    DECLARE @SQL NVARCHAR(MAX);
    DECLARE @StartTime DATETIME = GETDATE();
    DECLARE @StepStart DATETIME;
    DECLARE @StepTime DATETIME;
    DECLARE @ErrorMessage NVARCHAR(4000);
    DECLARE @DbName NVARCHAR(128) = DB_NAME();

    -- عدادات
    DECLARE @HeapsFixed INT = 0;
    DECLARE @IndexesRebuilt INT = 0;
    DECLARE @IndexesReorganized INT = 0;
    DECLARE @IndexesCreated INT = 0;
    DECLARE @IndexesDropped INT = 0;
    DECLARE @DuplicatesDropped INT = 0;
    DECLARE @StatsUpdated INT = 0;
    DECLARE @SettingsFixed INT = 0;
    DECLARE @ServerSettingsFixed INT = 0;

    -- ═══════════════════════════════════════════════════════════════
    -- جداول مؤقتة
    -- ═══════════════════════════════════════════════════════════════
    IF OBJECT_ID('tempdb..#OperationLog') IS NOT NULL DROP TABLE #OperationLog;
    CREATE TABLE #OperationLog (
        LogId INT IDENTITY(1,1),
        LogTime DATETIME DEFAULT GETDATE(),
        Operation NVARCHAR(100),
        ObjectName NVARCHAR(500),
        Details NVARCHAR(MAX),
        Duration_ms INT,
        Status NVARCHAR(20)
    );

    IF OBJECT_ID('tempdb..#Recommendations') IS NOT NULL DROP TABLE #Recommendations;
    CREATE TABLE #Recommendations (
        RecId INT IDENTITY(1,1),
        Category NVARCHAR(50),
        Priority NVARCHAR(20),
        Issue NVARCHAR(500),
        Recommendation NVARCHAR(MAX),
        Script NVARCHAR(MAX)
    );

    -- ═══════════════════════════════════════════════════════════════
    -- رسالة الترحيب
    -- ═══════════════════════════════════════════════════════════════
    PRINT '╔════════════════════════════════════════════════════════════════════════════╗';
    PRINT '║                                                                            ║';
    PRINT '║     ██████╗ ██████╗     ██████╗ ██████╗ ████████╗██╗███╗   ███╗██╗███████╗ ║';
    PRINT '║     ██╔══██╗██╔══██╗   ██╔═══██╗██╔══██╗╚══██╔══╝██║████╗ ████║██║╚══███╔╝ ║';
    PRINT '║     ██║  ██║██████╔╝   ██║   ██║██████╔╝   ██║   ██║██╔████╔██║██║  ███╔╝  ║';
    PRINT '║     ██║  ██║██╔══██╗   ██║   ██║██╔═══╝    ██║   ██║██║╚██╔╝██║██║ ███╔╝   ║';
    PRINT '║     ██████╔╝██████╔╝   ╚██████╔╝██║        ██║   ██║██║ ╚═╝ ██║██║███████╗ ║';
    PRINT '║     ╚═════╝ ╚═════╝     ╚═════╝ ╚═╝        ╚═╝   ╚═╝╚═╝     ╚═╝╚═╝╚══════╝ ║';
    PRINT '║                                                                            ║';
    PRINT '║              Ultimate Database Optimizer v4.0 + Auto-Fix                   ║';
    PRINT '║                                                                            ║';
    PRINT '╠════════════════════════════════════════════════════════════════════════════╣';
    PRINT '║  Database: ' + LEFT(@DbName + REPLICATE(' ', 65), 65) + '║';
    PRINT '║  Server:   ' + LEFT(@@SERVERNAME + REPLICATE(' ', 65), 65) + '║';
    PRINT '║  Started:  ' + LEFT(CONVERT(NVARCHAR(30), GETDATE(), 120) + REPLICATE(' ', 65), 65) + '║';
    PRINT '╚════════════════════════════════════════════════════════════════════════════╝';
    PRINT '';

    IF @PreviewOnly = 1
    BEGIN
        PRINT '══════════════════════════════════════════════════════════════════════════════';
        PRINT '   ⚠️  وضع المعاينة - PREVIEW MODE - لن يتم تنفيذ أي تغييرات';
        PRINT '══════════════════════════════════════════════════════════════════════════════';
        PRINT '';
    END

    --██████████████████████████████████████████████████████████████████████████████
    --█                                                                            █
    --█   ★★★ الخطوة الجديدة: إصلاح إعدادات السيرفر (MAXDOP, Memory, TempDB) ★★★   █
    --█                                                                            █
    --██████████████████████████████████████████████████████████████████████████████

    IF @FixServerSettings = 1
    BEGIN
        SET @StepStart = GETDATE();
        PRINT '┌────────────────────────────────────────────────────────────────────────────┐';
        PRINT '│  ★ إصلاح إعدادات السيرفر (MAXDOP, Memory, Parallelism)                    │';
        PRINT '└────────────────────────────────────────────────────────────────────────────┘';
        PRINT '';

        -- ═══════════════════════════════════════════════════════════════
        -- 1. إصلاح MAXDOP (حل مشكلة CXPACKET 32%)
        -- ═══════════════════════════════════════════════════════════════
        IF @FixParallelism = 1
        BEGIN
            DECLARE @CurrentMAXDOP INT;
            DECLARE @RecommendedMAXDOP INT;
            DECLARE @NumCPUs INT;
            DECLARE @NumNUMA INT;

            -- الحصول على عدد المعالجات
            SELECT @NumCPUs = cpu_count FROM sys.dm_os_sys_info;

            -- الحصول على عدد NUMA nodes
            SELECT @NumNUMA = COUNT(DISTINCT parent_node_id) 
            FROM sys.dm_os_schedulers 
            WHERE status = 'VISIBLE ONLINE';

            -- الحصول على MAXDOP الحالي
            SELECT @CurrentMAXDOP = CAST(value_in_use AS INT)
            FROM sys.configurations 
            WHERE name = 'max degree of parallelism';

            -- حساب MAXDOP المثالي
            -- القاعدة: لو أقل من 8 cores = عدد الـ cores
            --         لو أكثر من 8 = 8 أو نصف عدد الـ cores (الأقل)
            IF @NumCPUs <= 8
                SET @RecommendedMAXDOP = @NumCPUs;
            ELSE
                SET @RecommendedMAXDOP = 8;

            -- لو NUMA أكثر من 1، نقسم على عدد الـ NUMA
            IF @NumNUMA > 1
                SET @RecommendedMAXDOP = @NumCPUs / @NumNUMA;

            -- الحد الأقصى 8
            IF @RecommendedMAXDOP > 8
                SET @RecommendedMAXDOP = 8;

            PRINT '   📊 تحليل MAXDOP:';
            PRINT '      - عدد المعالجات (CPUs): ' + CAST(@NumCPUs AS VARCHAR(10));
            PRINT '      - عدد NUMA Nodes: ' + CAST(@NumNUMA AS VARCHAR(10));
            PRINT '      - MAXDOP الحالي: ' + CAST(@CurrentMAXDOP AS VARCHAR(10));
            PRINT '      - MAXDOP الموصى به: ' + CAST(@RecommendedMAXDOP AS VARCHAR(10));

            IF @CurrentMAXDOP = 0 OR @CurrentMAXDOP > @RecommendedMAXDOP
            BEGIN
                PRINT '      ⚠️ MAXDOP غير مضبوط - هذا يسبب مشكلة CXPACKET!';

                IF @PreviewOnly = 0
                BEGIN
                    BEGIN TRY
                        EXEC sp_configure 'show advanced options', 1;
                        RECONFIGURE;

                        SET @SQL = 'EXEC sp_configure ''max degree of parallelism'', ' + CAST(@RecommendedMAXDOP AS VARCHAR(10)) + ';';
                        EXEC (@SQL);
                        RECONFIGURE;

                        SET @ServerSettingsFixed = @ServerSettingsFixed + 1;
                        PRINT '      ✅ تم ضبط MAXDOP إلى ' + CAST(@RecommendedMAXDOP AS VARCHAR(10));

                        INSERT INTO #OperationLog (Operation, ObjectName, Details, Duration_ms, Status)
                        VALUES ('SET MAXDOP', 'Server Configuration', 
                               'Changed from ' + CAST(@CurrentMAXDOP AS VARCHAR(10)) + ' to ' + CAST(@RecommendedMAXDOP AS VARCHAR(10)),
                               DATEDIFF(MILLISECOND, @StepTime, GETDATE()), 'Success');
                    END TRY
                    BEGIN CATCH
                        PRINT '      ❌ خطأ: ' + ERROR_MESSAGE();

                        INSERT INTO #Recommendations (Category, Priority, Issue, Recommendation, Script)
                        VALUES ('Server Settings', 'CRITICAL', 
                                'MAXDOP = ' + CAST(@CurrentMAXDOP AS VARCHAR(10)) + ' يسبب CXPACKET waits',
                                'ضبط MAXDOP يدوياً',
                                'EXEC sp_configure ''max degree of parallelism'', ' + CAST(@RecommendedMAXDOP AS VARCHAR(10)) + '; RECONFIGURE;');
                    END CATCH
                END
                ELSE
                BEGIN
                    PRINT '      📝 سيتم تنفيذ: sp_configure ''max degree of parallelism'', ' + CAST(@RecommendedMAXDOP AS VARCHAR(10));
                END
            END
            ELSE
            BEGIN
                PRINT '      ✅ MAXDOP مضبوط بشكل صحيح';
            END

            PRINT '';

            -- ═══════════════════════════════════════════════════════════════
            -- 2. إصلاح Cost Threshold for Parallelism
            -- ═══════════════════════════════════════════════════════════════
            DECLARE @CurrentCostThreshold INT;
            DECLARE @RecommendedCostThreshold INT = 50; -- القيمة الموصى بها

            SELECT @CurrentCostThreshold = CAST(value_in_use AS INT)
            FROM sys.configurations 
            WHERE name = 'cost threshold for parallelism';

            PRINT '   📊 تحليل Cost Threshold for Parallelism:';
            PRINT '      - القيمة الحالية: ' + CAST(@CurrentCostThreshold AS VARCHAR(10));
            PRINT '      - القيمة الموصى بها: ' + CAST(@RecommendedCostThreshold AS VARCHAR(10));

            IF @CurrentCostThreshold < @RecommendedCostThreshold
            BEGIN
                PRINT '      ⚠️ القيمة منخفضة - تسبب parallelism مفرط!';

                IF @PreviewOnly = 0
                BEGIN
                    BEGIN TRY
                        SET @SQL = 'EXEC sp_configure ''cost threshold for parallelism'', ' + CAST(@RecommendedCostThreshold AS VARCHAR(10)) + ';';
                        EXEC (@SQL);
                        RECONFIGURE;

                        SET @ServerSettingsFixed = @ServerSettingsFixed + 1;
                        PRINT '      ✅ تم ضبط Cost Threshold إلى ' + CAST(@RecommendedCostThreshold AS VARCHAR(10));
                    END TRY
                    BEGIN CATCH
                        PRINT '      ❌ خطأ: ' + ERROR_MESSAGE();
                    END CATCH
                END
            END
            ELSE
            BEGIN
                PRINT '      ✅ Cost Threshold مضبوط بشكل صحيح';
            END

            PRINT '';
        END

        -- ═══════════════════════════════════════════════════════════════
        -- 3. تحسين إعدادات الذاكرة
        -- ═══════════════════════════════════════════════════════════════
        IF @OptimizeMemory = 1
        BEGIN
            DECLARE @TotalMemoryMB BIGINT;
            DECLARE @CurrentMaxMemory BIGINT;
            DECLARE @RecommendedMaxMemory BIGINT;
            DECLARE @OSReservedMB BIGINT;

            -- الحصول على الذاكرة الكلية
            SELECT @TotalMemoryMB = physical_memory_kb  / 1024 / 1024 
            FROM sys.dm_os_sys_info;

            -- الحصول على Max Server Memory الحالي
            SELECT @CurrentMaxMemory = CAST(value_in_use AS BIGINT)
            FROM sys.configurations 
            WHERE name = 'max server memory (MB)';

            -- حساب الذاكرة المثالية (نترك للـ OS حسب الحجم)
            -- أقل من 4 GB: نترك 1 GB
            -- 4-16 GB: نترك 2 GB
            -- 16-32 GB: نترك 4 GB
            -- أكثر من 32 GB: نترك 10%
            IF @TotalMemoryMB <= 4096
                SET @OSReservedMB = 1024;
            ELSE IF @TotalMemoryMB <= 16384
                SET @OSReservedMB = 2048;
            ELSE IF @TotalMemoryMB <= 32768
                SET @OSReservedMB = 4096;
            ELSE
                SET @OSReservedMB = @TotalMemoryMB / 10;

            SET @RecommendedMaxMemory = @TotalMemoryMB - @OSReservedMB;

            PRINT '   📊 تحليل الذاكرة:';
            PRINT '      - الذاكرة الكلية: ' + CAST(@TotalMemoryMB AS VARCHAR(20)) + ' MB';
            PRINT '      - Max Memory الحالي: ' + CAST(@CurrentMaxMemory AS VARCHAR(20)) + ' MB';
            PRINT '      - Max Memory الموصى به: ' + CAST(@RecommendedMaxMemory AS VARCHAR(20)) + ' MB';

            -- لو القيمة الافتراضية (2147483647) أو أكبر من الذاكرة المتاحة
            IF @CurrentMaxMemory > @TotalMemoryMB OR @CurrentMaxMemory = 2147483647
            BEGIN
                PRINT '      ⚠️ Max Memory غير محدد - يمكن أن يسبب مشاكل!';

                IF @PreviewOnly = 0
                BEGIN
                    BEGIN TRY
                        SET @SQL = 'EXEC sp_configure ''max server memory (MB)'', ' + CAST(@RecommendedMaxMemory AS VARCHAR(20)) + ';';
                        EXEC (@SQL);
                        RECONFIGURE;

                        SET @ServerSettingsFixed = @ServerSettingsFixed + 1;
                        PRINT '      ✅ تم ضبط Max Memory إلى ' + CAST(@RecommendedMaxMemory AS VARCHAR(20)) + ' MB';
                    END TRY
                    BEGIN CATCH
                        PRINT '      ❌ خطأ: ' + ERROR_MESSAGE();
                    END CATCH
                END
            END
            ELSE
            BEGIN
                PRINT '      ✅ Max Memory مضبوط';
            END

            PRINT '';
        END

        -- ═══════════════════════════════════════════════════════════════
        -- 4. فحص وإصلاح TempDB (حل مشكلة LATCH_EX 57%)
        -- ═══════════════════════════════════════════════════════════════
        IF @FixTempDB = 1
        BEGIN
            DECLARE @TempDBFiles INT;
            DECLARE @RecommendedTempDBFiles INT;

            -- عدد ملفات TempDB الحالية
            SELECT @TempDBFiles = COUNT(*) 
            FROM tempdb.sys.database_files 
            WHERE type = 0; -- Data files only

            -- عدد الملفات الموصى به = عدد المعالجات (بحد أقصى 8)
            SET @RecommendedTempDBFiles = CASE WHEN @NumCPUs > 8 THEN 8 ELSE @NumCPUs END;

            PRINT '   📊 تحليل TempDB (حل LATCH_EX):';
            PRINT '      - عدد ملفات TempDB الحالية: ' + CAST(@TempDBFiles AS VARCHAR(10));
            PRINT '      - عدد الملفات الموصى به: ' + CAST(@RecommendedTempDBFiles AS VARCHAR(10));

            IF @TempDBFiles < @RecommendedTempDBFiles
            BEGIN
                PRINT '      ⚠️ عدد ملفات TempDB قليل - يسبب LATCH_EX contention!';
                PRINT '';
                PRINT '      📋 لإصلاح هذه المشكلة، نفّذ الأوامر التالية يدوياً:';
                PRINT '';

                -- الحصول على مسار TempDB الحالي
                DECLARE @TempDBPath NVARCHAR(500);
                SELECT @TempDBPath = LEFT(physical_name, LEN(physical_name) - CHARINDEX('\', REVERSE(physical_name)) + 1)
                FROM tempdb.sys.database_files 
                WHERE type = 0 AND file_id = 1;

                -- الحصول على حجم الملف الحالي
                DECLARE @TempDBSizeMB INT;
                SELECT @TempDBSizeMB = size * 8 / 1024
                FROM tempdb.sys.database_files 
                WHERE type = 0 AND file_id = 1;

                DECLARE @FileNum INT = @TempDBFiles + 1;
                WHILE @FileNum <= @RecommendedTempDBFiles
                BEGIN
                    SET @SQL = 'ALTER DATABASE tempdb ADD FILE (NAME = ''tempdev' + CAST(@FileNum AS VARCHAR(2)) 
                              + ''', FILENAME = ''' + @TempDBPath + 'tempdb' + CAST(@FileNum AS VARCHAR(2)) 
                              + '.ndf'', SIZE = ' + CAST(@TempDBSizeMB AS VARCHAR(10)) + 'MB, FILEGROWTH = 64MB);';

                    PRINT '      ' + @SQL;

                    INSERT INTO #Recommendations (Category, Priority, Issue, Recommendation, Script)
                    VALUES ('TempDB', 'CRITICAL', 
                            'TempDB يحتوي على ' + CAST(@TempDBFiles AS VARCHAR(10)) + ' ملف فقط - يسبب LATCH_EX',
                            'إضافة ملف TempDB جديد رقم ' + CAST(@FileNum AS VARCHAR(2)),
                            @SQL);

                    SET @FileNum = @FileNum + 1;
                END

                PRINT '';
                PRINT '      ⚠️ ملاحظة: يُنصح بإعادة تشغيل SQL Server بعد إضافة الملفات';
            END
            ELSE
            BEGIN
                PRINT '      ✅ عدد ملفات TempDB مناسب';
            END

            PRINT '';
        END

        PRINT '   ═══ تم إصلاح ' + CAST(@ServerSettingsFixed AS VARCHAR(10)) + ' إعداد للسيرفر ═══';
        PRINT '';
    END

    --██████████████████████████████████████████████████████████████████████████████
    --█                                                                            █
    --█   الخطوة 0: فحص وإصلاح إعدادات قاعدة البيانات                              █
    --█                                                                            █
    --██████████████████████████████████████████████████████████████████████████████

    SET @StepStart = GETDATE();
    PRINT '┌────────────────────────────────────────────────────────────────────────────┐';
    PRINT '│  [0/10] 🔍 فحص وإصلاح إعدادات قاعدة البيانات                              │';
    PRINT '└────────────────────────────────────────────────────────────────────────────┘';
    PRINT '';

    -- فحص Auto-Shrink
    IF EXISTS (SELECT 1 FROM sys.databases WHERE database_id = DB_ID() AND is_auto_shrink_on = 1)
    BEGIN
        PRINT '   ❌ CRITICAL: Auto-Shrink مفعّل!';

        IF @FixDbSettings = 1 AND @PreviewOnly = 0
        BEGIN
            SET @SQL = 'ALTER DATABASE [' + @DbName + '] SET AUTO_SHRINK OFF;';
            BEGIN TRY
                EXEC (@SQL);
                PRINT '      ✅ تم إيقاف Auto-Shrink';
                SET @SettingsFixed = @SettingsFixed + 1;
            END TRY
            BEGIN CATCH
                PRINT '      ⚠️ فشل: ' + ERROR_MESSAGE();
            END CATCH
        END
    END
    ELSE
        PRINT '   ✅ Auto-Shrink: معطّل';

    -- فحص Auto-Close
    IF EXISTS (SELECT 1 FROM sys.databases WHERE database_id = DB_ID() AND is_auto_close_on = 1)
    BEGIN
        PRINT '   ⚠️ WARNING: Auto-Close مفعّل!';

        IF @FixDbSettings = 1 AND @PreviewOnly = 0
        BEGIN
            SET @SQL = 'ALTER DATABASE [' + @DbName + '] SET AUTO_CLOSE OFF;';
            BEGIN TRY
                EXEC (@SQL);
                PRINT '      ✅ تم إيقاف Auto-Close';
                SET @SettingsFixed = @SettingsFixed + 1;
            END TRY
            BEGIN CATCH
                PRINT '      ⚠️ فشل: ' + ERROR_MESSAGE();
            END CATCH
        END
    END
    ELSE
        PRINT '   ✅ Auto-Close: معطّل';

    -- فحص Auto Create Statistics
    IF EXISTS (SELECT 1 FROM sys.databases WHERE database_id = DB_ID() AND is_auto_create_stats_on = 0)
    BEGIN
        PRINT '   ❌ CRITICAL: Auto Create Statistics معطّل!';

        IF @FixDbSettings = 1 AND @PreviewOnly = 0
        BEGIN
            SET @SQL = 'ALTER DATABASE [' + @DbName + '] SET AUTO_CREATE_STATISTICS ON;';
            BEGIN TRY
                EXEC (@SQL);
                PRINT '      ✅ تم تفعيل Auto Create Statistics';
                SET @SettingsFixed = @SettingsFixed + 1;
            END TRY
            BEGIN CATCH
                PRINT '      ⚠️ فشل: ' + ERROR_MESSAGE();
            END CATCH
        END
    END
    ELSE
        PRINT '   ✅ Auto Create Statistics: مفعّل';

    -- فحص Auto Update Statistics
    IF EXISTS (SELECT 1 FROM sys.databases WHERE database_id = DB_ID() AND is_auto_update_stats_on = 0)
    BEGIN
        PRINT '   ❌ CRITICAL: Auto Update Statistics معطّل!';

        IF @FixDbSettings = 1 AND @PreviewOnly = 0
        BEGIN
            SET @SQL = 'ALTER DATABASE [' + @DbName + '] SET AUTO_UPDATE_STATISTICS ON;';
            BEGIN TRY
                EXEC (@SQL);
                PRINT '      ✅ تم تفعيل Auto Update Statistics';
                SET @SettingsFixed = @SettingsFixed + 1;
            END TRY
            BEGIN CATCH
                PRINT '      ⚠️ فشل: ' + ERROR_MESSAGE();
            END CATCH
        END
    END
    ELSE
        PRINT '   ✅ Auto Update Statistics: مفعّل';

    -- فحص Page Verify
    DECLARE @PageVerify NVARCHAR(60);
    SELECT @PageVerify = page_verify_option_desc FROM sys.databases WHERE database_id = DB_ID();

    IF @PageVerify <> 'CHECKSUM'
    BEGIN
        PRINT '   ⚠️ WARNING: Page Verify = ' + @PageVerify + ' (يجب أن يكون CHECKSUM)';

        IF @FixDbSettings = 1 AND @PreviewOnly = 0
        BEGIN
            SET @SQL = 'ALTER DATABASE [' + @DbName + '] SET PAGE_VERIFY CHECKSUM;';
            BEGIN TRY
                EXEC (@SQL);
                PRINT '      ✅ تم تغيير Page Verify إلى CHECKSUM';
                SET @SettingsFixed = @SettingsFixed + 1;
            END TRY
            BEGIN CATCH
                PRINT '      ⚠️ فشل: ' + ERROR_MESSAGE();
            END CATCH
        END
    END
    ELSE
        PRINT '   ✅ Page Verify: CHECKSUM';

    -- فحص Recovery Model
    DECLARE @RecoveryModel NVARCHAR(60);
    SELECT @RecoveryModel = recovery_model_desc FROM sys.databases WHERE database_id = DB_ID();
    PRINT '   📌 Recovery Model: ' + @RecoveryModel;

    -- ═══════════════════════════════════════════════════════════════
    -- فحص وإصلاح Transaction Log (حل WRITELOG)
    -- ═══════════════════════════════════════════════════════════════
    DECLARE @LogSizeMB DECIMAL(18,2) = 0;
    DECLARE @LogUsedMB DECIMAL(18,2) = 0;
    DECLARE @LogUsedPercent DECIMAL(5,2) = 0;

    SELECT 
        @LogSizeMB = SUM(CAST(size AS DECIMAL(18,2)) * 8 / 1024),
        @LogUsedMB = SUM(CAST(FILEPROPERTY(name, 'SpaceUsed') AS DECIMAL(18,2)) * 8 / 1024)
    FROM sys.database_files
    WHERE type_desc = 'LOG';

    IF @LogSizeMB > 0
        SET @LogUsedPercent = (@LogUsedMB / @LogSizeMB) * 100;

    PRINT '   📌 Transaction Log: ' + CAST(CAST(@LogUsedMB AS INT) AS VARCHAR(20)) + ' MB / ' 
          + CAST(CAST(@LogSizeMB AS INT) AS VARCHAR(20)) + ' MB (' 
          + CAST(CAST(@LogUsedPercent AS INT) AS VARCHAR(10)) + '%)';

    IF @LogUsedPercent > 70
    BEGIN
        PRINT '   ⚠️ WARNING: Transaction Log ممتلئ بنسبة ' + CAST(CAST(@LogUsedPercent AS INT) AS VARCHAR(10)) + '%';

        IF @ShrinkLogFile = 1 AND @PreviewOnly = 0
        BEGIN
            PRINT '      جاري تقليص Log File...';
            BEGIN TRY
                -- Checkpoint أولاً
                EXEC ('CHECKPOINT;');

                -- الحصول على اسم ملف الـ Log
                DECLARE @LogFileName NVARCHAR(128);
                SELECT @LogFileName = name FROM sys.database_files WHERE type_desc = 'LOG';

                -- لو Recovery Model = FULL، نحتاج Backup Log أولاً
                IF @RecoveryModel = 'FULL'
                BEGIN
                    PRINT '      جاري عمل Backup Log...';
                    SET @SQL = 'BACKUP LOG [' + @DbName + '] TO DISK = ''NUL'';';
                    EXEC (@SQL);
                END

                -- تقليص الـ Log
                SET @SQL = 'DBCC SHRINKFILE (N''' + @LogFileName + ''', 100);';
                EXEC (@SQL);

                PRINT '      ✅ تم تقليص Log File';

                INSERT INTO #OperationLog (Operation, ObjectName, Details, Duration_ms, Status)
                VALUES ('SHRINK LOG', @LogFileName, 
                       'Reduced from ' + CAST(CAST(@LogUsedPercent AS INT) AS VARCHAR(10)) + '%',
                       DATEDIFF(MILLISECOND, @StepTime, GETDATE()), 'Success');
            END TRY
            BEGIN CATCH
                PRINT '      ⚠️ فشل تقليص Log: ' + ERROR_MESSAGE();
            END CATCH
        END
    END

    PRINT '';
    PRINT '   ═══ تم إصلاح ' + CAST(@SettingsFixed AS VARCHAR(10)) + ' إعداد ═══';
    PRINT '';

    --██████████████████████████████████████████████████████████████████████████████
    --█                                                                            █
    --█   الخطوة 1: إصلاح الجداول Heap                                             █
    --█                                                                            █
    --██████████████████████████████████████████████████████████████████████████████

    IF @FixHeapTables = 1
    BEGIN
        SET @StepStart = GETDATE();
        PRINT '┌────────────────────────────────────────────────────────────────────────────┐';
        PRINT '│  [1/10] 🏗️ إصلاح الجداول Heap (إنشاء Clustered Index)                     │';
        PRINT '└────────────────────────────────────────────────────────────────────────────┘';
        PRINT '';

        IF OBJECT_ID('tempdb..#HeapTables') IS NOT NULL DROP TABLE #HeapTables;

        SELECT 
              s.name AS SchemaName
            , t.name AS TableName
            , SUM(p.rows) AS [RowCount]
            , SUM(a.total_pages) * 8 / 1024 AS SizeMB
            , CASE 
                WHEN EXISTS (
                    SELECT 1 FROM sys.columns c 
                    WHERE c.object_id = t.object_id 
                    AND c.is_identity = 1
                ) THEN (
                    SELECT TOP 1 c.name FROM sys.columns c 
                    WHERE c.object_id = t.object_id AND c.is_identity = 1
                )
                WHEN EXISTS (
                    SELECT 1 FROM sys.columns c 
                    WHERE c.object_id = t.object_id 
                    AND c.name LIKE '%ID' 
                    AND c.system_type_id IN (48, 52, 56, 127)
                ) THEN (
                    SELECT TOP 1 c.name FROM sys.columns c 
                    WHERE c.object_id = t.object_id 
                    AND c.name LIKE '%ID' 
                    AND c.system_type_id IN (48, 52, 56, 127)
                    ORDER BY c.column_id
                )
                WHEN EXISTS (
                    SELECT 1 FROM sys.columns c 
                    WHERE c.object_id = t.object_id 
                    AND c.column_id = 1
                    AND c.system_type_id IN (48, 52, 56, 127, 36)
                ) THEN (
                    SELECT c.name FROM sys.columns c 
                    WHERE c.object_id = t.object_id AND c.column_id = 1
                )
                ELSE NULL
              END AS SuggestedKeyColumn
        INTO #HeapTables
        FROM sys.tables t
        JOIN sys.schemas s ON t.schema_id = s.schema_id
        JOIN sys.partitions p ON t.object_id = p.object_id AND p.index_id = 0
        JOIN sys.allocation_units a ON p.partition_id = a.container_id
        WHERE t.is_ms_shipped = 0
          AND NOT EXISTS (
              SELECT 1 FROM sys.indexes i 
              WHERE i.object_id = t.object_id AND i.type = 1
          )
        GROUP BY s.name, t.name, t.object_id
        HAVING SUM(p.rows) >= @HeapMinRows
        ORDER BY SUM(p.rows) DESC;

        DECLARE @HeapCount INT;
        SELECT @HeapCount = COUNT(*) FROM #HeapTables;

        PRINT '   📊 تم العثور على ' + CAST(@HeapCount AS VARCHAR(10)) + ' جدول Heap';

        IF @HeapCount > 0
        BEGIN
            DECLARE 
                  @HSchemaName NVARCHAR(128)
                , @HTableName NVARCHAR(128)
                , @HRowCount BIGINT
                , @HSizeMB INT
                , @HKeyColumn NVARCHAR(128)
                , @HIndexName NVARCHAR(128);

            DECLARE curHeaps CURSOR LOCAL FAST_FORWARD FOR
                SELECT SchemaName, TableName, [RowCount], SizeMB, SuggestedKeyColumn
                FROM #HeapTables
                WHERE SuggestedKeyColumn IS NOT NULL
                ORDER BY [RowCount] DESC;

            OPEN curHeaps;
            FETCH NEXT FROM curHeaps INTO @HSchemaName, @HTableName, @HRowCount, @HSizeMB, @HKeyColumn;

            WHILE @@FETCH_STATUS = 0
            BEGIN
                SET @StepTime = GETDATE();
                SET @HIndexName = 'CIX_' + @HTableName;

                SET @SQL = 'CREATE CLUSTERED INDEX [' + @HIndexName + '] ON [' 
                          + @HSchemaName + '].[' + @HTableName + '] ([' + @HKeyColumn + ']) '
                          + 'WITH (FILLFACTOR = ' + CAST(@FillFactor AS VARCHAR(3)) + ');';

                IF @VerboseOutput = 1
                    PRINT '   📦 ' + @HSchemaName + '.' + @HTableName 
                          + ' | Rows: ' + CAST(@HRowCount AS VARCHAR(20)) 
                          + ' | Key: ' + @HKeyColumn;

                IF @PreviewOnly = 0
                BEGIN
                    BEGIN TRY
                        EXEC (@SQL);
                        SET @HeapsFixed = @HeapsFixed + 1;
                        PRINT '      ✅ تم إنشاء Clustered Index';
                    END TRY
                    BEGIN CATCH
                        PRINT '      ❌ خطأ: ' + ERROR_MESSAGE();
                    END CATCH
                END

                FETCH NEXT FROM curHeaps INTO @HSchemaName, @HTableName, @HRowCount, @HSizeMB, @HKeyColumn;
            END

            CLOSE curHeaps;
            DEALLOCATE curHeaps;
        END

        PRINT '';
        PRINT '   ═══ تم إصلاح ' + CAST(@HeapsFixed AS VARCHAR(10)) + ' جدول Heap ═══';
        PRINT '';
    END

    --██████████████████████████████████████████████████████████████████████████████
    --█                                                                            █
    --█   الخطوة 2: صيانة الإندكسات (Rebuild / Reorganize)                         █
    --█                                                                            █
    --██████████████████████████████████████████████████████████████████████████████

    SET @StepStart = GETDATE();
    PRINT '┌────────────────────────────────────────────────────────────────────────────┐';
    PRINT '│  [2/10] 🔧 صيانة الإندكسات (Rebuild / Reorganize)                         │';
    PRINT '└────────────────────────────────────────────────────────────────────────────┘';
    PRINT '';

    IF OBJECT_ID('tempdb..#IndexFragmentation') IS NOT NULL DROP TABLE #IndexFragmentation;

    SELECT 
          t.name                              AS TableName
        , s.name                              AS SchemaName
        , i.name                              AS IndexName
        , i.index_id                          AS IndexId
        , i.type_desc                         AS IndexType
        , ips.avg_fragmentation_in_percent    AS FragPercent
        , ips.page_count                      AS PageCount
        , ips.record_count                    AS RecordCount
        , CASE 
            WHEN ips.avg_fragmentation_in_percent >= @RebuildThreshold THEN 'REBUILD'
            WHEN ips.avg_fragmentation_in_percent >= @ReorganizeThreshold THEN 'REORGANIZE'
            ELSE 'OK'
          END AS RecommendedAction
    INTO #IndexFragmentation
    FROM sys.dm_db_index_physical_stats(DB_ID(), NULL, NULL, NULL, 'LIMITED') ips
    JOIN sys.indexes i   ON ips.object_id = i.object_id AND ips.index_id = i.index_id
    JOIN sys.tables t    ON t.object_id  = i.object_id
    JOIN sys.schemas s   ON t.schema_id = s.schema_id
    WHERE 
        i.type IN (1, 2)
        AND ips.page_count >= @MinPageCount
        AND t.is_ms_shipped = 0
        AND i.is_disabled = 0
        AND i.name IS NOT NULL;

    DECLARE @TotalIndexes INT, @NeedRebuild INT, @NeedReorg INT;
    SELECT @TotalIndexes = COUNT(*) FROM #IndexFragmentation;
    SELECT @NeedRebuild = COUNT(*) FROM #IndexFragmentation WHERE RecommendedAction = 'REBUILD';
    SELECT @NeedReorg = COUNT(*) FROM #IndexFragmentation WHERE RecommendedAction = 'REORGANIZE';

    PRINT '   📊 ملخص: إجمالي ' + CAST(@TotalIndexes AS VARCHAR(10)) 
          + ' | REBUILD: ' + CAST(@NeedRebuild AS VARCHAR(10)) 
          + ' | REORGANIZE: ' + CAST(@NeedReorg AS VARCHAR(10));

    DECLARE 
          @ITableName   SYSNAME
        , @ISchemaName  SYSNAME
        , @IIndexName   SYSNAME
        , @IIndexId     INT
        , @IFrag        FLOAT
        , @IPageCount   BIGINT
        , @IAction      NVARCHAR(20);

    DECLARE curIndexMaint CURSOR LOCAL FAST_FORWARD FOR
        SELECT TableName, SchemaName, IndexName, IndexId, FragPercent, PageCount, RecommendedAction
        FROM #IndexFragmentation
        WHERE RecommendedAction IN ('REBUILD', 'REORGANIZE')
        ORDER BY PageCount DESC;

    OPEN curIndexMaint;
    FETCH NEXT FROM curIndexMaint INTO @ITableName, @ISchemaName, @IIndexName, @IIndexId, @IFrag, @IPageCount, @IAction;

    WHILE @@FETCH_STATUS = 0
    BEGIN
        SET @StepTime = GETDATE();

        IF @IAction = 'REBUILD'
        BEGIN
            IF @OnlineRebuild = 1
                SET @SQL = N'ALTER INDEX [' + @IIndexName + N'] ON [' + @ISchemaName + N'].[' 
                          + @ITableName + N'] REBUILD WITH (ONLINE = ON, FILLFACTOR = ' + CAST(@FillFactor AS VARCHAR(3)) + ');';
            ELSE
                SET @SQL = N'ALTER INDEX [' + @IIndexName + N'] ON [' + @ISchemaName + N'].[' 
                          + @ITableName + N'] REBUILD WITH (FILLFACTOR = ' + CAST(@FillFactor AS VARCHAR(3)) + ');';
        END
        ELSE
            SET @SQL = N'ALTER INDEX [' + @IIndexName + N'] ON [' + @ISchemaName + N'].[' + @ITableName + N'] REORGANIZE;';

        IF @VerboseOutput = 1
            PRINT '   ' + @IAction + ' | ' + CAST(CAST(@IFrag AS INT) AS VARCHAR(5)) + '% | ' + @ISchemaName + '.' + @ITableName + '.' + @IIndexName;

        IF @PreviewOnly = 0
        BEGIN
            BEGIN TRY
                EXEC (@SQL);
                IF @IAction = 'REBUILD'
                    SET @IndexesRebuilt = @IndexesRebuilt + 1;
                ELSE
                    SET @IndexesReorganized = @IndexesReorganized + 1;
            END TRY
            BEGIN CATCH
                SET @ErrorMessage = ERROR_MESSAGE();
                PRINT '      ❌ خطأ: ' + @ErrorMessage;
            END CATCH
        END

        FETCH NEXT FROM curIndexMaint INTO @ITableName, @ISchemaName, @IIndexName, @IIndexId, @IFrag, @IPageCount, @IAction;
    END

    CLOSE curIndexMaint;
    DEALLOCATE curIndexMaint;

    PRINT '';
    PRINT '   ═══ REBUILD: ' + CAST(@IndexesRebuilt AS VARCHAR(10)) + ' | REORGANIZE: ' + CAST(@IndexesReorganized AS VARCHAR(10)) + ' ═══';
    PRINT '';

    --██████████████████████████████████████████████████████████████████████████████
    --█                                                                            █
    --█   الخطوة 3: إنشاء الإندكسات الناقصة                                        █
    --█                                                                            █
    --██████████████████████████████████████████████████████████████████████████████

    IF @CreateMissingIndexes = 1
    BEGIN
        SET @StepStart = GETDATE();
        PRINT '┌────────────────────────────────────────────────────────────────────────────┐';
        PRINT '│  [3/10] 🆕 إنشاء الإندكسات الناقصة                                        │';
        PRINT '└────────────────────────────────────────────────────────────────────────────┘';
        PRINT '';

        IF OBJECT_ID('tempdb..#MissingIndexes') IS NOT NULL DROP TABLE #MissingIndexes;

        SELECT TOP (@MaxMissingIndexesToCreate)
              OBJECT_SCHEMA_NAME(mid.object_id, mid.database_id)          AS SchemaName
            , OBJECT_NAME(mid.object_id, mid.database_id)                 AS TableName
            , (migs.user_seeks + migs.user_scans)                         AS TotalReads
            , migs.avg_user_impact                                        AS AvgUserImpact
            , CAST(migs.avg_total_user_cost * migs.avg_user_impact 
                   * (migs.user_seeks + migs.user_scans) AS DECIMAL(18,2)) AS ImprovementScore
            , mid.equality_columns                                        AS EqualityColumns
            , mid.inequality_columns                                      AS InequalityColumns
            , mid.included_columns                                        AS IncludedColumns
            , 'IX_Auto_' 
              + REPLACE(REPLACE(REPLACE(OBJECT_NAME(mid.object_id, mid.database_id), ' ', '_'), '-', '_'), '.', '_')
              + '_' + CAST(mig.index_group_handle AS VARCHAR(10))         AS IndexName
            , 'CREATE NONCLUSTERED INDEX [IX_Auto_' 
              + REPLACE(REPLACE(REPLACE(OBJECT_NAME(mid.object_id, mid.database_id), ' ', '_'), '-', '_'), '.', '_')
              + '_' + CAST(mig.index_group_handle AS VARCHAR(10))
              + '] ON [' + OBJECT_SCHEMA_NAME(mid.object_id, mid.database_id) + '].['
              + OBJECT_NAME(mid.object_id, mid.database_id) + '] ('
              + ISNULL(mid.equality_columns, '')
              + CASE WHEN mid.equality_columns IS NOT NULL AND mid.inequality_columns IS NOT NULL THEN ', ' ELSE '' END
              + ISNULL(mid.inequality_columns, '')
              + ')'
              + CASE WHEN mid.included_columns IS NOT NULL THEN ' INCLUDE (' + mid.included_columns + ')' ELSE '' END
              + ' WITH (FILLFACTOR = ' + CAST(@FillFactor AS VARCHAR(3)) + ');' AS CreateStatement
        INTO #MissingIndexes
        FROM sys.dm_db_missing_index_group_stats AS migs
        JOIN sys.dm_db_missing_index_groups AS mig ON migs.group_handle = mig.index_group_handle
        JOIN sys.dm_db_missing_index_details AS mid ON mig.index_handle = mid.index_handle
        WHERE mid.database_id = DB_ID()
          AND (migs.user_seeks + migs.user_scans) >= @MissingIndexMinReads
          AND migs.avg_user_impact >= @MissingIndexMinImpact
        ORDER BY ImprovementScore DESC;

        DECLARE @MissingCount INT;
        SELECT @MissingCount = COUNT(*) FROM #MissingIndexes;

        PRINT '   📊 تم العثور على ' + CAST(@MissingCount AS VARCHAR(10)) + ' إندكس مقترح';

        IF @MissingCount > 0
        BEGIN
            DECLARE 
                  @MISchemaName       NVARCHAR(128)
                , @MITableName        NVARCHAR(128)
                , @MIIndexName        NVARCHAR(128)
                , @MICreateStatement  NVARCHAR(MAX)
                , @MIAvgImpact        FLOAT;

            DECLARE curMissing CURSOR LOCAL FAST_FORWARD FOR
                SELECT SchemaName, TableName, IndexName, CreateStatement, AvgUserImpact
                FROM #MissingIndexes
                ORDER BY ImprovementScore DESC;

            OPEN curMissing;
            FETCH NEXT FROM curMissing INTO @MISchemaName, @MITableName, @MIIndexName, @MICreateStatement, @MIAvgImpact;

            WHILE @@FETCH_STATUS = 0
            BEGIN
                SET @StepTime = GETDATE();

                IF @VerboseOutput = 1
                    PRINT '   📈 Impact: ' + CAST(CAST(@MIAvgImpact AS INT) AS VARCHAR(10)) + '% | ' + @MISchemaName + '.' + @MITableName;

                IF @PreviewOnly = 0
                BEGIN
                    IF NOT EXISTS (
                        SELECT 1 FROM sys.indexes 
                        WHERE object_id = OBJECT_ID(@MISchemaName + '.' + @MITableName)
                          AND name = @MIIndexName
                    )
                    BEGIN
                        BEGIN TRY
                            EXEC (@MICreateStatement);
                            SET @IndexesCreated = @IndexesCreated + 1;
                            PRINT '      ✅ تم الإنشاء';
                        END TRY
                        BEGIN CATCH
                            PRINT '      ❌ خطأ: ' + ERROR_MESSAGE();
                        END CATCH
                    END
                END

                FETCH NEXT FROM curMissing INTO @MISchemaName, @MITableName, @MIIndexName, @MICreateStatement, @MIAvgImpact;
            END

            CLOSE curMissing;
            DEALLOCATE curMissing;
        END

        PRINT '';
        PRINT '   ═══ تم إنشاء ' + CAST(@IndexesCreated AS VARCHAR(10)) + ' إندكس جديد ═══';
        PRINT '';
    END

    --██████████████████████████████████████████████████████████████████████████████
    --█                                                                            █
    --█   الخطوة 4-5: حذف الإندكسات المكررة وغير المستخدمة                         █
    --█                                                                            █
    --██████████████████████████████████████████████████████████████████████████████

    IF @DropDuplicateIndexes = 1
    BEGIN
        PRINT '┌────────────────────────────────────────────────────────────────────────────┐';
        PRINT '│  [4/10] 🗑️ حذف الإندكسات المكررة                                          │';
        PRINT '└────────────────────────────────────────────────────────────────────────────┘';

        IF OBJECT_ID('tempdb..#DuplicateIndexes') IS NOT NULL DROP TABLE #DuplicateIndexes;

        ;WITH IndexColumns AS
        (
            SELECT 
                  i.object_id, i.index_id
                , s.name AS SchemaName, t.name AS TableName, i.name AS IndexName
                , i.is_primary_key, i.is_unique_constraint
                , (SELECT CAST(ic.column_id AS VARCHAR(10)) + CASE WHEN ic.is_descending_key = 1 THEN 'D' ELSE 'A' END + ','
                   FROM sys.index_columns ic WHERE ic.object_id = i.object_id AND ic.index_id = i.index_id AND ic.is_included_column = 0
                   ORDER BY ic.key_ordinal FOR XML PATH('')) AS KeyColumns
            FROM sys.indexes i
            JOIN sys.tables t ON i.object_id = t.object_id
            JOIN sys.schemas s ON t.schema_id = s.schema_id
            WHERE i.type IN (1, 2) AND t.is_ms_shipped = 0 AND i.name IS NOT NULL
        )
        SELECT ic1.SchemaName, ic1.TableName, ic1.IndexName AS DuplicateIndex, ic2.IndexName AS OriginalIndex,
               'DROP INDEX [' + ic1.IndexName + '] ON [' + ic1.SchemaName + '].[' + ic1.TableName + '];' AS DropStatement
        INTO #DuplicateIndexes
        FROM IndexColumns ic1
        JOIN IndexColumns ic2 ON ic1.object_id = ic2.object_id AND ic1.index_id > ic2.index_id AND ic1.KeyColumns = ic2.KeyColumns
        WHERE ic1.is_primary_key = 0 AND ic1.is_unique_constraint = 0;

        DECLARE @DupCount INT;
        SELECT @DupCount = COUNT(*) FROM #DuplicateIndexes;
        PRINT '   📊 تم العثور على ' + CAST(@DupCount AS VARCHAR(10)) + ' إندكس مكرر';

        IF @DupCount > 0 AND @PreviewOnly = 0
        BEGIN
            DECLARE @DDropStatement NVARCHAR(MAX);
            DECLARE curDups CURSOR LOCAL FAST_FORWARD FOR SELECT DropStatement FROM #DuplicateIndexes;
            OPEN curDups;
            FETCH NEXT FROM curDups INTO @DDropStatement;
            WHILE @@FETCH_STATUS = 0
            BEGIN
                BEGIN TRY
                    EXEC (@DDropStatement);
                    SET @DuplicatesDropped = @DuplicatesDropped + 1;
                END TRY
                BEGIN CATCH
                END CATCH
                FETCH NEXT FROM curDups INTO @DDropStatement;
            END
            CLOSE curDups;
            DEALLOCATE curDups;
        END

        PRINT '   ═══ تم حذف ' + CAST(@DuplicatesDropped AS VARCHAR(10)) + ' إندكس مكرر ═══';
        PRINT '';
    END

    --██████████████████████████████████████████████████████████████████████████████
    --█                                                                            █
    --█   الخطوة 6: تحديث الإحصائيات                                               █
    --█                                                                            █
    --██████████████████████████████████████████████████████████████████████████████

    IF @UpdateStatistics = 1
    BEGIN
        PRINT '┌────────────────────────────────────────────────────────────────────────────┐';
        PRINT '│  [6/10] 📊 تحديث الإحصائيات                                               │';
        PRINT '└────────────────────────────────────────────────────────────────────────────┘';

        IF OBJECT_ID('tempdb..#StaleStats') IS NOT NULL DROP TABLE #StaleStats;

        SELECT 
              s.name AS SchemaName, t.name AS TableName, st.name AS StatName
            , DATEDIFF(DAY, STATS_DATE(st.object_id, st.stats_id), GETDATE()) AS DaysSinceUpdate
        INTO #StaleStats
        FROM sys.stats st
        JOIN sys.tables t ON st.object_id = t.object_id
        JOIN sys.schemas s ON t.schema_id = s.schema_id
        JOIN sys.partitions p ON t.object_id = p.object_id AND p.index_id IN (0, 1)
        WHERE t.is_ms_shipped = 0
          AND (STATS_DATE(st.object_id, st.stats_id) < DATEADD(DAY, -3, GETDATE()) OR STATS_DATE(st.object_id, st.stats_id) IS NULL)
        GROUP BY s.name, t.name, st.name, st.object_id, st.stats_id
        HAVING SUM(p.rows) > 0;

        DECLARE @StaleStatsCount INT;
        SELECT @StaleStatsCount = COUNT(*) FROM #StaleStats;
        PRINT '   📊 تم العثور على ' + CAST(@StaleStatsCount AS VARCHAR(10)) + ' إحصائية تحتاج تحديث';

        IF @StaleStatsCount > 0 AND @PreviewOnly = 0
        BEGIN
            DECLARE @SSSchemaName SYSNAME, @SSTableName SYSNAME, @SSStatName SYSNAME;
            DECLARE curStats CURSOR LOCAL FAST_FORWARD FOR SELECT SchemaName, TableName, StatName FROM #StaleStats;
            OPEN curStats;
            FETCH NEXT FROM curStats INTO @SSSchemaName, @SSTableName, @SSStatName;
            WHILE @@FETCH_STATUS = 0
            BEGIN
                BEGIN TRY
                    SET @SQL = N'UPDATE STATISTICS [' + @SSSchemaName + '].[' + @SSTableName + '] ([' + @SSStatName + ']) WITH SAMPLE 50 PERCENT;';
                    EXEC (@SQL);
                    SET @StatsUpdated = @StatsUpdated + 1;
                END TRY
                BEGIN CATCH
                END CATCH
                FETCH NEXT FROM curStats INTO @SSSchemaName, @SSTableName, @SSStatName;
            END
            CLOSE curStats;
            DEALLOCATE curStats;
        END

        PRINT '   ═══ تم تحديث ' + CAST(@StatsUpdated AS VARCHAR(10)) + ' إحصائية ═══';
        PRINT '';
    END

    --██████████████████████████████████████████████████████████████████████████████
    --█                                                                            █
    --█   الخطوة 7: مسح خطط التنفيذ السيئة                                         █
    --█                                                                            █
    --██████████████████████████████████████████████████████████████████████████████

    IF @ClearBadPlans = 1
    BEGIN
        PRINT '┌────────────────────────────────────────────────────────────────────────────┐';
        PRINT '│  [7/10] 🧹 مسح خطط التنفيذ السيئة                                         │';
        PRINT '└────────────────────────────────────────────────────────────────────────────┘';

        IF @PreviewOnly = 0
        BEGIN
            BEGIN TRY
                DBCC FREEPROCCACHE;
                PRINT '   ✅ تم مسح Plan Cache';
            END TRY
            BEGIN CATCH
                PRINT '   ⚠️ فشل: ' + ERROR_MESSAGE();
            END CATCH
        END
        PRINT '';
    END

    --██████████████████████████████████████████████████████████████████████████████
    --█                                                                            █
    --█   الخطوة 8: تحليل Wait Statistics                                          █
    --█                                                                            █
    --██████████████████████████████████████████████████████████████████████████████

    IF @AnalyzeWaitStats = 1
    BEGIN
        PRINT '┌────────────────────────────────────────────────────────────────────────────┐';
        PRINT '│  [8/10] ⏱️ تحليل Wait Statistics                                          │';
        PRINT '└────────────────────────────────────────────────────────────────────────────┘';
        PRINT '';

        ;WITH WaitStats AS
        (
            SELECT 
                  wait_type
                , waiting_tasks_count
                , wait_time_ms
                , signal_wait_time_ms
                , wait_time_ms - signal_wait_time_ms AS resource_wait_time_ms
                , 100.0 * wait_time_ms / NULLIF(SUM(wait_time_ms) OVER(), 0) AS wait_percentage
            FROM sys.dm_os_wait_stats
            WHERE wait_type NOT IN (
                'LAZYWRITER_SLEEP', 'BROKER_TASK_STOP', 'BROKER_EVENTHANDLER',
                'SQLTRACE_BUFFER_FLUSH', 'CLR_AUTO_EVENT', 'CLR_MANUAL_EVENT',
                'REQUEST_FOR_DEADLOCK_SEARCH', 'XE_TIMER_EVENT', 'XE_DISPATCHER_WAIT',
                'FT_IFTS_SCHEDULER_IDLE_WAIT', 'BROKER_TO_FLUSH', 'XE_DISPATCHER_JOIN',
                'DBMIRROR_DBM_EVENT', 'DBMIRRORING_CMD', 'DIRTY_PAGE_POLL',
                'HADR_FILESTREAM_IOMGR_IOCOMPLETION', 'SP_SERVER_DIAGNOSTICS_SLEEP',
                'SLEEP_TASK', 'SLEEP_SYSTEMTASK', 'SQLTRACE_INCREMENTAL_FLUSH_SLEEP',
                'WAITFOR', 'LOGMGR_QUEUE', 'CHECKPOINT_QUEUE', 'ONDEMAND_TASK_QUEUE',
                'WAIT_XTP_OFFLINE_CKPT_NEW_LOG', 'CLR_SEMAPHORE', 'DISPATCHER_QUEUE_SEMAPHORE',
                'BROKER_RECEIVE_WAITFOR', 'PREEMPTIVE_XE_GETTARGETSTATE', 'PREEMPTIVE_XE_SESSIONCOMMIT',
                'PREEMPTIVE_XE_TARGETINIT', 'PREEMPTIVE_XE_TARGETFINALIZE'
            )
            AND waiting_tasks_count > 0
        )
        SELECT TOP 15
              [Wait Type] = wait_type
            , [Wait %] = CAST(wait_percentage AS DECIMAL(5,2))
            , [Total Wait (sec)] = CAST(wait_time_ms / 1000.0 AS DECIMAL(18,2))
            , [Wait Count] = waiting_tasks_count
            , [Recommendation] = CASE 
                WHEN wait_type LIKE 'LATCH%' THEN '*** TempDB contention - Add TempDB files ***'
                WHEN wait_type LIKE 'CXPACKET%' OR wait_type = 'CXCONSUMER' THEN '*** Set MAXDOP properly ***'
                WHEN wait_type LIKE 'PAGEIOLATCH%' THEN 'I/O Problem - Check disk'
                WHEN wait_type LIKE 'LCK%' THEN 'Locking - Review queries'
                WHEN wait_type = 'SOS_SCHEDULER_YIELD' THEN 'CPU Pressure'
                WHEN wait_type = 'WRITELOG' THEN 'Log I/O - Shrink log'
                ELSE 'Review documentation'
              END
        FROM WaitStats
        WHERE wait_percentage > 0.1
        ORDER BY wait_percentage DESC;

        PRINT '';
    END

    --██████████████████████████████████████████████████████████████████████████████
    --█                                                                            █
    --█   الخطوة 9: عرض الاستعلامات الأكثر بطئاً                                   █
    --█                                                                            █
    --██████████████████████████████████████████████████████████████████████████████

    PRINT '┌────────────────────────────────────────────────────────────────────────────┐';
    PRINT '│  [9/10] 🐢 أبطأ الاستعلامات                                               │';
    PRINT '└────────────────────────────────────────────────────────────────────────────┘';

    SELECT TOP (@TopQueries)
          [Rank] = ROW_NUMBER() OVER (ORDER BY qs.total_elapsed_time DESC)
        , [Avg Duration (ms)] = qs.total_elapsed_time / NULLIF(qs.execution_count, 0) / 1000
        , [Executions] = qs.execution_count
        , [Avg Reads] = qs.total_logical_reads / NULLIF(qs.execution_count, 0)
        , [Object] = ISNULL(OBJECT_NAME(st.objectid, st.dbid), 'Ad-hoc')
        , [Query] = SUBSTRING(st.text, (qs.statement_start_offset/2)+1,
                    ((CASE qs.statement_end_offset WHEN -1 THEN DATALENGTH(st.text) ELSE qs.statement_end_offset END - qs.statement_start_offset)/2)+1)
    FROM sys.dm_exec_query_stats qs
    CROSS APPLY sys.dm_exec_sql_text(qs.sql_handle) st
    WHERE st.dbid = DB_ID() AND qs.execution_count > 0
    ORDER BY qs.total_elapsed_time DESC;

    PRINT '';

    --██████████████████████████████████████████████████████████████████████████████
    --█                                                                            █
    --█   الخطوة 10: مسح Wait Stats (اختياري)                                      █
    --█                                                                            █
    --██████████████████████████████████████████████████████████████████████████████

    IF @ClearWaitStats = 1 AND @PreviewOnly = 0
    BEGIN
        PRINT '┌────────────────────────────────────────────────────────────────────────────┐';
        PRINT '│  [10/10] 🔄 مسح Wait Statistics للبدء من جديد                             │';
        PRINT '└────────────────────────────────────────────────────────────────────────────┘';

        BEGIN TRY
            DBCC SQLPERF ('sys.dm_os_wait_stats', CLEAR);
            PRINT '   ✅ تم مسح Wait Statistics';
        END TRY
        BEGIN CATCH
            PRINT '   ⚠️ فشل: ' + ERROR_MESSAGE();
        END CATCH
        PRINT '';
    END

    --██████████████████████████████████████████████████████████████████████████████
    --█                                                                            █
    --█   التقرير النهائي                                                          █
    --█                                                                            █
    --██████████████████████████████████████████████████████████████████████████████

    PRINT '╔════════════════════════════════════════════════════════════════════════════╗';
    PRINT '║                            📊 ملخص العمليات                               ║';
    PRINT '╠════════════════════════════════════════════════════════════════════════════╣';
    PRINT '║  إعدادات السيرفر المُصلحة:      ' + LEFT(CAST(@ServerSettingsFixed AS VARCHAR(10)) + REPLICATE(' ', 43), 43) + '║';
    PRINT '║  إعدادات الداتا بيز المُصلحة:   ' + LEFT(CAST(@SettingsFixed AS VARCHAR(10)) + REPLICATE(' ', 43), 43) + '║';
    PRINT '║  جداول Heap المُصلحة:           ' + LEFT(CAST(@HeapsFixed AS VARCHAR(10)) + REPLICATE(' ', 43), 43) + '║';
    PRINT '║  إندكسات REBUILD:               ' + LEFT(CAST(@IndexesRebuilt AS VARCHAR(10)) + REPLICATE(' ', 43), 43) + '║';
    PRINT '║  إندكسات REORGANIZE:            ' + LEFT(CAST(@IndexesReorganized AS VARCHAR(10)) + REPLICATE(' ', 43), 43) + '║';
    PRINT '║  إندكسات جديدة:                 ' + LEFT(CAST(@IndexesCreated AS VARCHAR(10)) + REPLICATE(' ', 43), 43) + '║';
    PRINT '║  إندكسات مكررة محذوفة:          ' + LEFT(CAST(@DuplicatesDropped AS VARCHAR(10)) + REPLICATE(' ', 43), 43) + '║';
    PRINT '║  إحصائيات محدّثة:               ' + LEFT(CAST(@StatsUpdated AS VARCHAR(10)) + REPLICATE(' ', 43), 43) + '║';
    PRINT '╠════════════════════════════════════════════════════════════════════════════╣';
    PRINT '║  وقت التنفيذ:                   ' + LEFT(CAST(DATEDIFF(SECOND, @StartTime, GETDATE()) AS VARCHAR(10)) + ' ثانية' + REPLICATE(' ', 33), 43) + '║';
    PRINT '╚════════════════════════════════════════════════════════════════════════════╝';

    -- عرض التوصيات
    IF EXISTS (SELECT 1 FROM #Recommendations)
    BEGIN
        PRINT '';
        PRINT '╔════════════════════════════════════════════════════════════════════════════╗';
        PRINT '║                     📝 توصيات تحتاج تنفيذ يدوي                            ║';
        PRINT '╚════════════════════════════════════════════════════════════════════════════╝';

        SELECT Priority, Category, Issue, Recommendation, Script
        FROM #Recommendations
        ORDER BY CASE Priority WHEN 'CRITICAL' THEN 1 WHEN 'HIGH' THEN 2 ELSE 3 END;
    END

    PRINT '';
    PRINT '════════════════════════════════════════════════════════════════════════════════';
    PRINT '   ✅ انتهى تنفيذ Ultimate Database Optimizer';
    PRINT '════════════════════════════════════════════════════════════════════════════════';

    -- تنظيف
    IF OBJECT_ID('tempdb..#OperationLog') IS NOT NULL DROP TABLE #OperationLog;
    IF OBJECT_ID('tempdb..#Recommendations') IS NOT NULL DROP TABLE #Recommendations;
    IF OBJECT_ID('tempdb..#HeapTables') IS NOT NULL DROP TABLE #HeapTables;
    IF OBJECT_ID('tempdb..#IndexFragmentation') IS NOT NULL DROP TABLE #IndexFragmentation;
    IF OBJECT_ID('tempdb..#MissingIndexes') IS NOT NULL DROP TABLE #MissingIndexes;
    IF OBJECT_ID('tempdb..#DuplicateIndexes') IS NOT NULL DROP TABLE #DuplicateIndexes;
    IF OBJECT_ID('tempdb..#StaleStats') IS NOT NULL DROP TABLE #StaleStats;

END
